export enum ModelType {
  GEMINI = 'GEMINI',
  OPENAI_COMPATIBLE = 'OPENAI_COMPATIBLE'
}

export interface ModelConfig {
  id: string;
  name: string;
  type: ModelType;
  endpoint?: string; // For OpenAI compatible
  apiKey?: string; // For OpenAI compatible (user provided)
  modelId: string; // The actual model string ID sent to API
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  timestamp: number;
}

export interface Session {
  id: string;
  name: string;
  basePrompt: string;
  referenceImages: string[]; // Base64 strings
  generatedImages: GeneratedImage[];
  generatedPrompts: string[];
  createdAt: number;
  status: 'idle' | 'generating' | 'completed' | 'failed';
  totalTarget: number;
  progress: number;
  logs: string[];
}

export interface GenerationSettings {
  count: number;
  modelId: string;
  expandPrompts: boolean; // Whether to use LLM to diversify prompts
}

import { GoogleGenAI, Type } from "@google/genai";
import { ModelConfig, ModelType } from "../types";

// --- Gemini Implementation ---

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Google GenAI API Key not found in environment.");
  return new GoogleGenAI({ apiKey });
};

export const generateDiversePrompts = async (
  basePrompt: string, 
  count: number,
  referenceImagesCount: number
): Promise<string[]> => {
  try {
    const ai = getGeminiClient();

    // We use Flash for text logic as it's fast and efficient
    const model = "gemini-3-flash-preview"; 

    const systemInstruction = `You are a synthetic data specialist for Computer Vision. 
    Your goal is to generate diverse, detailed visual descriptions (prompts) based on a user's base concept. 
    This is for Domain Randomization. Vary lighting, background, camera angles, weather, and object placement 
    while keeping the core subject consistent.

    User has provided ${referenceImagesCount} reference images. 

    Output a JSON array of strings. Each string is a prompt.`;

    const response = await ai.models.generateContent({
      model,
      contents: `Generate ${count} diverse prompts for: "${basePrompt}"`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const text = response.text;
    if (!text) return Array(count).fill(basePrompt);

    return JSON.parse(text) as string[];
  } catch (error) {
    console.error("Error expanding prompts:", error);
    // Fallback: just return the base prompt N times if expansion fails
    return Array(count).fill(basePrompt);
  }
};

export const generateImageWithGemini = async (
  prompt: string,
  referenceImagesBase64: string[],
  onImageFound: (base64: string) => void
): Promise<void> => {
  const ai = getGeminiClient();
  // Mapping "Nanobanana Pro" logic to the correct model ID per instructions
  const model = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // Add reference images
  referenceImagesBase64.forEach(base64 => {
    // Strip prefix if present (e.g., data:image/png;base64,)
    const cleanBase64 = base64.split(',')[1] || base64;
    parts.push({
      inlineData: {
        mimeType: 'image/png', // Assuming PNG for simplicity, usually safe for upload logic
        data: cleanBase64
      }
    });
  });

  // Add the text prompt
  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts },
      config: {
        // Image generation config
        imageConfig: {
            aspectRatio: "1:1", 
            imageSize: "1K" 
        }
      }
    });

    // Extract image
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          const mime = part.inlineData.mimeType || 'image/png';
          const fullBase64 = `data:${mime};base64,${part.inlineData.data}`;
          onImageFound(fullBase64);
          return;
        }
      }
    }
    throw new Error("No image data found in response");
  } catch (err) {
    console.error("Gemini Image Gen Error:", err);
    throw err;
  }
};

// --- Custom OpenAI Compatible Implementation (Simulated for Structure) ---

export const generateImageCustom = async (
  config: ModelConfig,
  prompt: string,
  onImageFound: (urlOrBase64: string) => void
) => {
  if (!config.endpoint || !config.apiKey) {
    throw new Error("Missing endpoint or API key for custom model");
  }

  // Generic DALL-E style interface
  const response = await fetch(`${config.endpoint}/v1/images/generations`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${config.apiKey}`
    },
    body: JSON.stringify({
      model: config.modelId,
      prompt: prompt,
      n: 1,
      size: "1024x1024",
      response_format: "b64_json"
    })
  });

  if (!response.ok) {
    const err = await response.text();
    throw new Error(`Custom API Error: ${err}`);
  }

  const data = await response.json();
  const b64 = data.data?.[0]?.b64_json;

  if (b64) {
    onImageFound(`data:image/png;base64,${b64}`);
  } else {
    // Try url if b64 not present
    const url = data.data?.[0]?.url;
    if (url) onImageFound(url);
    else throw new Error("No image found in custom API response");
  }
};

