                {/* Logs Terminal */}
                <div className="bg-black/50 rounded-lg p-3 font-mono text-xs text-slate-400 h-32 overflow-y-auto border border-slate-800/50">
                   {activeSession.logs.map((log, i) => (
                     <div key={i} className="mb-1">{log}</div>
                   ))}
                   <div id="log-end"></div>
                </div>
              </div>

              {/* Gallery */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg font-semibold text-white">Generated Dataset</h3>
                  {activeSession.generatedImages.length > 0 && (
                    <button 
                      onClick={() => downloadAll(activeSession)}
