                    >
                       <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="7 10 12 15 17 10"></polyline><line x1="12" y1="15" x2="12" y2="3"></line></svg>
                       Download Dataset
                    </button>
                  )}
                </div>

                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                  {activeSession.generatedImages.map((img) => (
                     <div key={img.id} className="group relative aspect-square bg-slate-900 rounded-lg border border-slate-800 overflow-hidden hover:border-primary-500/50 transition-colors">
                        <img src={img.url} alt="gen" className="w-full h-full object-cover" />
