                           <p className="text-xs text-slate-300 line-clamp-2 mb-2">{img.prompt}</p>
                           <a 
                             href={img.url} 
                             download={`synth_${img.id}.png`}
                             className="bg-white/10 hover:bg-white/20 backdrop-blur text-white text-xs py-1.5 px-3 rounded flex items-center justify-center gap-2 transition-colors"
                           >
                              Download
                           </a>
                        </div>
                     </div>
                  ))}
                  {/* Skeletons for pending */}
                  {activeSession.status === 'generating' && Array.from({ length: Math.max(0, activeSession.totalTarget - activeSession.generatedImages.length) }).map((_, i) => (
                    <div key={`skel-${i}`} className="aspect-square bg-slate-900/50 rounded-lg border border-slate-800/50 flex items-center justify-center animate-pulse">
                      <svg className="w-8 h-8 text-slate-700" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                      </svg>
