                  {activeSession.generatedPrompts.map((p, i) => (
                    <div key={i} className="text-sm text-slate-400 bg-black/30 p-3 rounded border border-slate-800/50">
                       <span className="text-primary-500 font-mono mr-2">[{i+1}]</span>
                       {p}
                    </div>
                  ))}
                  {activeSession.generatedPrompts.length === 0 && (
                     <div className="text-sm text-slate-600 italic">Prompts will appear here once synthesized...</div>
                  )}
                </div>
              </div>

            </div>
          )}
        </div>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        configs={modelConfigs}
        activeConfigId={activeModelId}
        onSaveConfig={(config) => setModelConfigs(prev => [...prev, config])}
        onSelectActive={(id) => setActiveModelId(id)}
      />
    </div>
  );
};

export default App;

