import { GoogleGenAI, Type } from "@google/genai";
import { ModelConfig, ModelType } from "../types";

// --- Gemini Implementation ---

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Google GenAI API Key not found in environment.");
  return new GoogleGenAI({ apiKey });
};

export const generateDiversePrompts = async (
  basePrompt: string, 
  count: number,
  referenceImagesCount: number
): Promise<string[]> => {
  try {
    const ai = getGeminiClient();

    // We use Flash for text logic as it's fast and efficient
    const model = "gemini-3-flash-preview"; 

    const systemInstruction = `You are a synthetic data specialist for Computer Vision. 
    Your goal is to generate ${count} variations of the user's prompt to create a training dataset.

    CRITICAL RULES:
    1. **Strict Adherence**: You MUST PRESERVE all specific constraints provided in the user's prompt. 
       - If a specific angle is requested (e.g., "top-down", "isometric"), ALL generated prompts MUST use that angle.
       - If specific foreground object features are described (e.g., "red helmet", "rusted metal"), ALL prompts MUST include them.
       - Do NOT modify or remove core subject definitions.

    2. **Multi-Image Logic**: The user has provided ${referenceImagesCount} reference images. 
       - The user may refer to them as "Ref 1", "Image 1", "Ref 2", "second image", etc.
       - These references correspond to the specific order of the provided images.
       - **MANDATORY**: If the user prompt says "Use Ref 1 for face and Ref 2 for style", you MUST preserve these exact references or textually describe the correspondence (e.g. "using the face from the first reference image...").
       - Do NOT randomize which reference image corresponds to which part of the prompt if the user explicitly defined it.

    3. **Domain Randomization**: Only vary attributes that are NOT explicitly defined by the user.
       - Vary lighting (e.g., sunset, studio, overcast).
       - Vary background/environment (e.g., city, forest, white background).
       - Vary weather or time of day.

    4. **Reference Context**: Your prompts should focus on placing the subject(s) from the provided references into different contexts while maintaining the strict requirements above.

    Output strictly a JSON array of strings.`;

    const response = await ai.models.generateContent({
      model,
      contents: `Generate ${count} diverse prompts based on: "${basePrompt}"`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    const text = response.text;
    if (!text) return Array(count).fill(basePrompt);

    return JSON.parse(text) as string[];
  } catch (error) {
    console.error("Error expanding prompts:", error);
    // Fallback: just return the base prompt N times if expansion fails
    return Array(count).fill(basePrompt);
  }
};

export const generateImageWithGemini = async (
  prompt: string,
  referenceImagesBase64: string[],
  onImageFound: (base64: string) => void
): Promise<void> => {
  const ai = getGeminiClient();
  // Mapping "Nanobanana Pro" logic to the correct model ID per instructions
  const model = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // Add reference images
  referenceImagesBase64.forEach(base64 => {
    // Strip prefix if present (e.g., data:image/png;base64,)
    const cleanBase64 = base64.split(',')[1] || base64;
    parts.push({
      inlineData: {
        mimeType: 'image/png', // Assuming PNG for simplicity, usually safe for upload logic
        data: cleanBase64
      }
    });
  });

  // Add the text prompt
  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts },
      config: {
        // Image generation config
        imageConfig: {
            aspectRatio: "1:1", 
            imageSize: "1K" 
        }
      }
    });

    // Extract image
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          const mime = part.inlineData.mimeType || 'image/png';
          const fullBase64 = `data:${mime};base64,${part.inlineData.data}`;
          onImageFound(fullBase64);
          return;
        }
      }
    }
    throw new Error("No image data found in response");
  } catch (err) {
    console.error("Gemini Image Gen Error:", err);
    throw err;
  }
};

