import { GoogleGenAI, Type } from "@google/genai";
import { ModelConfig, ModelType } from "../types";

// --- Gemini Implementation ---

const getGeminiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Google GenAI API Key not found in environment.");
  return new GoogleGenAI({ apiKey });
};

export const generateDiversePrompts = async (
  basePrompt: string, 
  count: number,
  referenceImagesCount: number
): Promise<{ prompts: string[], aspectRatio: string }> => {
  try {
    const ai = getGeminiClient();

    // We use Flash for text logic as it's fast and efficient
    const model = "gemini-3-flash-preview"; 

    const systemInstruction = `You are a professional synthetic data engineer specializing in Computer Vision training sets. 
    Your task is to generate ${count} prompt variations based on the user's requirement.

    CRITICAL CONSTRAINTS:
    1. **Language & Translation**: 
       - If the user provides input in Chinese, accurately translate it into a high-quality, descriptive English "Core Subject".
       - All output prompts MUST be in English.

    2. **Consistency (Immutable Core)**:
       - You must identify the "Core Subject" and "Mandatory Features" from the user input.
       - These elements MUST remain IDENTICAL across all ${count} generated prompts. 
       - Do NOT add artistic flair or change the subject's properties (color, material, pose, specific details) unless explicitly asked to vary them.

    3. **Domain Randomization (The ONLY allowed variables)**:
       - ONLY vary the environment, lighting, weather, and camera-related artifacts.
       - Environment: e.g., urban street, industrial warehouse, rural forest, laboratory, white studio.
       - Lighting: e.g., harsh midday sun, dim twilight, fluorescent office lights, cinematic backlighting.
       - Weather/Atmosphere: e.g., heavy rain, foggy, clear sky, dusty.
       - Artifacts: e.g., clean lens, slight motion blur, surveillance camera grain.

    4. **Image Ratio & Dimensions**:
       - Scan the user input for specific ratio or size keywords (e.g., "16:9", "horizontal", "vertical", "9:16", "3:4", "landscape").
       - If a specific ratio is found, you MUST return it in the 'aspectRatio' field.
       - Supported ratios: ["1:1", "3:4", "4:3", "9:16", "16:9"].
       - If no ratio is mentioned, default to "1:1".

    5. **Reference Mapping**:
       - Maintain references to "Ref 1", "Ref 2", etc., if the user used them to describe specific objects.

    FORMAT:
    Each prompt should follow this structure: "[Core Subject with User Constraints], [Randomized Domain Environment/Lighting/Weather]".

    Output strictly a JSON object:
    {
      "prompts": ["string", "string", ...],
      "aspectRatio": "1:1" | "3:4" | "4:3" | "9:16" | "16:9"
    }`;

    const response = await ai.models.generateContent({
      model,
      contents: `User Input: "${basePrompt}". Generate ${count} variations.`,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            prompts: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            aspectRatio: {
              type: Type.STRING,
              enum: ["1:1", "3:4", "4:3", "9:16", "16:9"]
            }
          },
          required: ["prompts", "aspectRatio"]
        }
      }
    });

    const text = response.text;
    if (!text) return { prompts: Array(count).fill(basePrompt), aspectRatio: "1:1" };

    return JSON.parse(text) as { prompts: string[], aspectRatio: string };
  } catch (error) {
    console.error("Error expanding prompts:", error);
    return { prompts: Array(count).fill(basePrompt), aspectRatio: "1:1" };
  }
};

export const generateImageWithGemini = async (
  prompt: string,
  referenceImagesBase64: string[],
  aspectRatio: string,
  onImageFound: (base64: string) => void
): Promise<void> => {
  const ai = getGeminiClient();
  const model = "gemini-3-pro-image-preview"; 

  const parts: any[] = [];

  // Add reference images
  referenceImagesBase64.forEach(base64 => {
    const cleanBase64 = base64.split(',')[1] || base64;
    parts.push({
      inlineData: {
        mimeType: 'image/png', 
        data: cleanBase64
      }
    });
  });

  // Add the text prompt
  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { parts },
      config: {
        imageConfig: {
            aspectRatio: aspectRatio as any, 
            imageSize: "1K" 
        }
      }
    });

    // Extract image
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          const mime = part.inlineData.mimeType || 'image/png';
          const fullBase64 = `data:${mime};base64,${part.inlineData.data}`;
          onImageFound(fullBase64);
          return;
        }
      }
    }
    throw new Error("No image data found in response");
  } catch (err) {
    console.error("Gemini Image Gen Error:", err);
    throw err;
  }
};

export const generateImageCustom = async (
  config: ModelConfig,
  prompt: string,
  aspectRatio: string,
  onImageFound: (urlOrBase64: string) => void
) => {
  if (!config.endpoint || !config.apiKey) {
    throw new Error("Missing endpoint or API key for custom model");
  }

  let size = "1024x1024";
  if (aspectRatio === "16:9") size = "1792x1024";
  if (aspectRatio === "9:16") size = "1024x1792";

  const response = await fetch(`${config.endpoint}/v1/images/generations`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${config.apiKey}`
    },
    body: JSON.stringify({
      model: config.modelId,
      prompt: prompt,
      n: 1,
      size: size, 
      response_format: "b64_json"
    })
  });

  if (!response.ok) {
    const err = await response.text();
    throw new Error(`Custom API Error: ${err}`);
  }

  const data = await response.json();
  const b64 = data.data?.[0]?.b64_json;

  if (b64) {
    onImageFound(`data:image/png;base64,${b64}`);
  } else {
    const url = data.data?.[0]?.url;
    if (url) onImageFound(url);
    else throw new Error("No image found in custom API response");
  }
};

