                    <div className="flex justify-between items-center">
                        <label className="text-sm font-medium text-slate-300">Reference Images (Max 4)</label>
                        <span className="text-xs text-slate-500">{refImages.length}/4</span>
                    </div>
                    <div className="grid grid-cols-4 gap-2">
                        {refImages.map((img, idx) => (
                        <div key={idx} className="aspect-square rounded-lg border border-slate-700 overflow-hidden relative group bg-slate-800">
                            <img src={img} alt="ref" className="w-full h-full object-contain" />
                            <div className="absolute top-1 left-1 bg-black/60 backdrop-blur-sm text-white text-[10px] px-1.5 py-0.5 rounded border border-white/20 font-mono shadow-sm">
                                REF {idx + 1}
                            </div>
                            <button 
                                onClick={() => setRefImages(prev => prev.filter((_, i) => i !== idx))}
                                className="absolute top-1 right-1 bg-black/60 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500/80"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                            </button>
                        </div>
                        ))}
                        {refImages.length < 4 && (
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="aspect-square rounded-lg border-2 border-dashed border-slate-700 hover:border-primary-500 hover:bg-slate-800 transition-all flex flex-col items-center justify-center text-slate-500 hover:text-primary-400 cursor-pointer"
                        >
                            <span className="text-xl">+</span>
                        </button>
                        )}
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />
                  </div>

                  <div className="lg:col-span-6 space-y-3">
                    <label className="text-sm font-medium text-slate-300">Scenario Description</label>
                    <textarea 
                        value={promptInput}
                        onChange={(e) => setPromptInput(e.target.value)}
                        placeholder="Describe the desired output. To refer to specific images, use 'Ref 1', 'Ref 2', etc. Example: 'A robot (Ref 1) holding the skateboard (Ref 2) in a neon city...'"
                        className="w-full h-24 bg-slate-800 border border-slate-700 rounded-xl p-3 text-sm text-white placeholder-slate-500 focus:border-primary-500 outline-none resize-none"
                    />
                  </div>

                  <div className="lg:col-span-2 space-y-3 flex flex-col">
                    <label className="text-sm font-medium text-slate-300">Count</label>
                    <select 
                        value={genCount}
                        onChange={(e) => setGenCount(Number(e.target.value))}
                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-sm text-white outline-none"
                    >
                        {COUNT_OPTIONS.map(opt => <option key={opt} value={opt}>{opt} Images</option>)}
                    </select>
                    <button 
                        onClick={createSession}
                        disabled={!promptInput.trim()}
                        className="mt-auto w-full bg-primary-600 hover:bg-primary-500 disabled:opacity-50 disabled:cursor-not-allowed text-white text-sm font-semibold py-3 rounded-lg shadow-lg transition-all"
                    >
                        Start Generation
                    </button>
                  </div>
               </div>
            </div>

            {activeSession && (
                <div className="p-6 pb-20 max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="h-px bg-slate-800 flex-1"></div>
                        <span className="text-slate-500 text-xs font-medium uppercase tracking-widest">Results</span>
                        <div className="h-px bg-slate-800 flex-1"></div>
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 mb-8 relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/5 rounded-full blur-3xl pointer-events-none -mr-16 -mt-16"></div>

                        <div className="flex justify-between items-end mb-4 relative z-10">
                            <div>
                                <div className="text-xs text-slate-400 uppercase tracking-wide font-bold mb-1">Current Task</div>
                                <div className={`text-2xl font-bold flex items-center gap-3 ${
                                    activeSession.status === 'completed' ? 'text-green-400' : 
                                    activeSession.status === 'failed' ? 'text-red-400' : 
                                    'text-white'
                                }`}>
                                    {activeSession.status === 'generating' ? 'Generating...' : activeSession.status.charAt(0).toUpperCase() + activeSession.status.slice(1)}

                                    {activeSession.status === 'generating' && (
                                    <button 
                                        onClick={() => stopGeneration(activeSession.id)}
                                        className="bg-red-500/20 hover:bg-red-500/30 text-red-500 text-xs px-3 py-1 rounded-full border border-red-500/50 transition-colors"
                                    >
                                        Stop
                                    </button>
                                    )}
                                </div>
                            </div>
                            <div className="text-right">
                                <div className="text-3xl font-mono text-white">
                                {activeSession.generatedImages.length}<span className="text-slate-500 text-lg">/{activeSession.totalTarget}</span>
                                </div>
                            </div>
                        </div>

                        <div className="h-2 bg-slate-800 rounded-full overflow-hidden mb-6 relative z-10">
                            <div 
                                className={`h-full transition-all duration-500 ease-out ${activeSession.status === 'stopped' ? 'bg-yellow-600' : 'bg-gradient-to-r from-primary-600 to-purple-500'}`}
                                style={{ width: `${activeSession.progress}%` }}
                            ></div>
                        </div>

                         <div className="bg-black/40 rounded-lg p-3 font-mono text-xs text-slate-400 h-24 overflow-y-auto border border-slate-800/50">
                            {activeSession.logs.map((log, i) => (
                                <div key={i} className="mb-1">{log}</div>
                            ))}
                        </div>
                    </div>

                    <div className="flex items-center justify-between mb-4">
                        <div className="flex gap-2">
                            {uniqueTags.length > 0 && (
                            <select 
                                value={activeFilterTag || ''} 
                                onChange={(e) => setActiveFilterTag(e.target.value || null)}
                                className="bg-slate-800 text-white text-xs border border-slate-700 rounded px-2 py-2 outline-none"
                            >
                                <option value="">All Tags</option>
                                {uniqueTags.map(tag => (
                                <option key={tag} value={tag}>{tag}</option>
                                ))}
                            </select>
                            )}
                        </div>
                        {filteredImages.length > 0 && (
                            <button 
                                onClick={downloadVisible}
                                className="text-sm text-slate-300 hover:text-white flex items-center gap-2 px-3 py-1 rounded hover:bg-slate-800 transition-colors"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="7 10 12 15 17 10"></polyline><line x1="12" y1="15" x2="12" y2="3"></line></svg>
                                Download
                            </button>
                        )}
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredImages.map((img) => (
                            <div 
                                key={img.id} 
                                onClick={() => setEditingImage(img)}
                                className="group relative aspect-square bg-slate-900 rounded-lg border border-slate-800 overflow-hidden hover:border-primary-500/50 transition-colors cursor-pointer flex items-center justify-center"
                            >
                                <img src={img.url} alt="gen" className="w-full h-full object-contain p-1" />
                                {img.tags.length > 0 && (
                                <div className="absolute top-2 left-2 flex gap-1 flex-wrap max-w-full">
                                    {img.tags.slice(0, 2).map(tag => (
                                        <span key={tag} className="bg-black/60 backdrop-blur text-white text-[10px] px-1.5 py-0.5 rounded border border-white/10">
                                        {tag}
                                        </span>
                                    ))}
                                    {img.tags.length > 2 && <span className="bg-black/60 text-white text-[10px] px-1.5 py-0.5 rounded">+{img.tags.length - 2}</span>}
                                </div>
                                )}
                                <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-3">
                                   <div className="text-xs text-white bg-primary-600 px-2 py-1 rounded shadow">Edit</div>
                                </div>
                            </div>
                        ))}
                        {activeSession.status === 'generating' && !activeFilterTag && Array.from({ length: Math.max(0, activeSession.totalTarget - activeSession.generatedImages.length) }).map((_, i) => (
                            <div key={`skel-${i}`} className="aspect-square bg-slate-900/50 rounded-lg border border-slate-800/50 flex items-center justify-center animate-pulse">
                                <svg className="w-6 h-6 text-slate-700" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                            </div>
                        ))}
                    </div>

                     <div className="mt-8 pt-6 border-t border-slate-800">
                        <h4 className="text-sm font-semibold text-slate-400 mb-3">Synthesized Prompt Variations</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                             {activeSession.generatedPrompts.map((p, i) => (
                                <div key={i} className="text-xs text-slate-500 bg-slate-900 p-2 rounded border border-slate-800 truncate" title={p}>
                                    {p}
                                </div>
                             ))}
                        </div>
                     </div>
                </div>
            )}

            {!activeSession && (
                <div className="h-64 flex flex-col items-center justify-center text-slate-600 space-y-4">
                    <p>Enter details above and start a new generation task.</p>
                </div>
            )}
        </div>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        configs={modelConfigs}
        activeConfigId={activeModelId}
        onSaveConfig={(config) => setModelConfigs(prev => [...prev, config])}
        onSelectActive={(id) => setActiveModelId(id)}
      />

      <ImageEditorModal 
        image={editingImage} 
        onClose={() => setEditingImage(null)}
        onSave={handleImageSave}
      />
    </div>
  );
};

