          className="absolute left-[calc(100%+12px)] top-4 w-80 bg-slate-900/95 backdrop-blur-md border border-slate-700 rounded-xl shadow-2xl p-5 z-50 animate-in fade-in slide-in-from-left-4 duration-300 border-l-4 border-l-primary-500"
          onMouseEnter={() => setHoveredSessionId(detailedSession.id)}
          onMouseLeave={() => setHoveredSessionId(null)}
        >
          <div className="flex justify-between items-center mb-3">
            <div className="text-[10px] text-primary-400 font-bold uppercase tracking-widest">Dataset Configuration</div>
            <button 
              onClick={() => {
                navigator.clipboard.writeText(detailedSession.basePrompt);
              }}
              className="text-[10px] bg-slate-800 hover:bg-slate-700 text-slate-300 px-2 py-1 rounded transition-colors flex items-center gap-1"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
              Copy
            </button>
          </div>
          <div className="bg-black/40 rounded-lg p-3 max-h-80 overflow-y-auto border border-slate-800/50">
            <p className="text-xs text-slate-200 leading-relaxed whitespace-pre-wrap font-sans">
              {detailedSession.basePrompt}
            </p>
          </div>
          <div className="mt-4 pt-3 border-t border-slate-800 flex flex-col gap-1 text-[10px] text-slate-500">
             <div className="flex justify-between">
                <span>Created At</span>
                <span className="text-slate-400">{new Date(detailedSession.createdAt).toLocaleString()}</span>
             </div>
             <div className="flex justify-between">
                <span>Total Target</span>
                <span className="text-slate-400">{detailedSession.totalTarget} Samples</span>
             </div>
             <div className="flex justify-between">
                <span>Status</span>
                <span className={`capitalize ${detailedSession.status === 'completed' ? 'text-green-500' : 'text-primary-400'}`}>{detailedSession.status}</span>
             </div>
          </div>
          {pinnedSessionId === detailedSession.id && (
            <button 
              onClick={() => setPinnedSessionId(null)}
              className="mt-3 w-full py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-400 text-[10px] rounded border border-slate-700 transition-colors"
            >
              Close Details
            </button>
          )}
        </div>
      )}

      <div className="p-4 border-t border-slate-800 text-[10px] text-slate-500 text-center tracking-tight">
        DATA FORGE ENGINE <span className="text-slate-600 font-mono">v1.2</span>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import SettingsModal from './components/SettingsModal';
import ImageEditorModal from './components/ImageEditorModal';
import { Session, GeneratedImage, ModelConfig, ModelType } from './types';
import { generateDiversePrompts, generateImageWithGemini, generateImageCustom } from './services/api';

// Declare window interface for AI Studio
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
}

const DEFAULT_MODEL: ModelConfig = {
  id: 'default-gemini',
  name: 'Nanobanana Pro (Default)',
  type: ModelType.GEMINI,
  modelId: 'gemini-3-pro-image-preview'
};

const COUNT_OPTIONS = [1, 2, 4, 8, 10, 20, 50];

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [isCheckingKey, setIsCheckingKey] = useState<boolean>(true);
  const [isDragging, setIsDragging] = useState<boolean>(false);

  const [sessions, setSessions] = useState<Session[]>([]);

  // Ref to track latest sessions state for async operations
  const sessionsRef = useRef(sessions);
  useEffect(() => {
    sessionsRef.current = sessions;
  }, [sessions]);

  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [activeModelId, setActiveModelId] = useState<string>(DEFAULT_MODEL.id);
  const [modelConfigs, setModelConfigs] = useState<ModelConfig[]>([DEFAULT_MODEL]);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Editor & Filtering State
  const [editingImage, setEditingImage] = useState<GeneratedImage | null>(null);
  const [activeFilterTag, setActiveFilterTag] = useState<string | null>(null);

  // Refs for generation control
  const abortControllerRef = useRef<boolean>(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Input State
  const [promptInput, setPromptInput] = useState('');
  const [refImages, setRefImages] = useState<string[]>([]);
  const [genCount, setGenCount] = useState<number>(4);

  // Check API Key on Mount
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        try {
          const hasSelected = await window.aistudio.hasSelectedApiKey();
          setHasApiKey(hasSelected);
        } catch (e) {
          console.error("Failed to check API key status", e);
          setHasApiKey(true);
        }
      } else {
        setHasApiKey(true);
      }
      setIsCheckingKey(false);
    };
    checkKey();
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setHasApiKey(true);
      } catch (e) {
        console.error("Failed to select key", e);
      }
    }
  };

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;
  const activeModel = modelConfigs.find(m => m.id === activeModelId) || DEFAULT_MODEL;

  const handleNewSession = () => {
    setActiveSessionId(null);
    setPromptInput('');
    setRefImages([]);
    setGenCount(4);
    setActiveFilterTag(null);
  };

  const handleSelectSession = (id: string) => {
    const session = sessions.find(s => s.id === id);
    if (session) {
      setActiveSessionId(id);
      setPromptInput(session.basePrompt);
      setRefImages(session.referenceImages);
      setGenCount(session.totalTarget);
      setActiveFilterTag(null);
    }
  };

  const createSession = () => {
    const newSession: Session = {
      id: Date.now().toString(),
      name: promptInput.substring(0, 30) || 'Untitled Task',
      basePrompt: promptInput,
      referenceImages: [...refImages],
      generatedImages: [],
      generatedPrompts: [],
      createdAt: Date.now(),
      status: 'idle',
      totalTarget: genCount,
      progress: 0,
      logs: ['Session initialized. Waiting to start...']
    };

    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setActiveFilterTag(null);

    setTimeout(() => {
        startGeneration(newSession.id);
    }, 100);
  };

  const updateSession = (id: string, updates: Partial<Session>) => {
    setSessions(prev => prev.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const addLog = (sessionId: string, message: string) => {
    setSessions(prev => prev.map(s => {
      if (s.id === sessionId) {
        return { ...s, logs: [...s.logs, `[${new Date().toLocaleTimeString()}] ${message}`] };
      }
      return s;
    }));
  };

  const stopGeneration = (sessionId: string) => {
    abortControllerRef.current = true;
    updateSession(sessionId, { status: 'stopped' });
    addLog(sessionId, "User interrupted the generation process.");
  };

  const startGeneration = async (sessionId: string) => {
    const session = sessionsRef.current.find(s => s.id === sessionId);
    if (!session) return;

    abortControllerRef.current = false;
    updateSession(sessionId, { status: 'generating', progress: 5, logs: [] });
    addLog(sessionId, `Starting generation task for ${session.totalTarget} images.`);

    try {
      addLog(sessionId, "Synthesizing diverse prompts & analyzing constraints...");

      let diversePrompts: string[];
      let aspectRatio: string;

      try {
        const result = await generateDiversePrompts(
          session.basePrompt, 
          session.totalTarget, 
          session.referenceImages.length
        );
        diversePrompts = result.prompts;
        aspectRatio = result.aspectRatio;
      } catch (expansionError: any) {
        addLog(sessionId, `Warning: Prompt expansion failed: ${expansionError.message}. Using original prompt as fallback.`);
        diversePrompts = Array(session.totalTarget).fill(session.basePrompt);
        aspectRatio = "16:9"; // Default fallback
      }

      if (abortControllerRef.current) return;

      updateSession(sessionId, { generatedPrompts: diversePrompts, progress: 15 });
      addLog(sessionId, `Generated ${diversePrompts.length} unique variations.`);
      addLog(sessionId, `Target Aspect Ratio: ${aspectRatio}`);

      let completedCount = 0;
      for (let i = 0; i < diversePrompts.length; i++) {
        if (abortControllerRef.current) break;

        const prompt = diversePrompts[i];
        addLog(sessionId, `Generating image ${i + 1}/${diversePrompts.length}...`);

        try {
          const handleImageResult = (base64OrUrl: string) => {
            const newImage: GeneratedImage = {
              id: `${sessionId}_${Date.now()}_${i}`,
              url: base64OrUrl,
              prompt: prompt,
              timestamp: Date.now(),
              tags: []
            };

            setSessions(prev => {
                const current = prev.find(s => s.id === sessionId);
                if(!current) return prev;
                const updatedImages = [...current.generatedImages, newImage];
                const newProgress = 15 + Math.floor((updatedImages.length / current.totalTarget) * 85);
                return prev.map(s => s.id === sessionId ? {
                    ...s,
                    generatedImages: updatedImages,
                    progress: newProgress
                } : s);
            });
          };

          if (activeModel.type === ModelType.GEMINI) {
            await generateImageWithGemini(prompt, session.referenceImages, aspectRatio, handleImageResult);
          } else {
            await generateImageCustom(activeModel, prompt, aspectRatio, handleImageResult);
          }
        } catch (err: any) {
          console.error("Generation Loop Error:", err);
          addLog(sessionId, `Error generating image ${i + 1}: ${err.message}`);
        }
        completedCount++;
      }

      if (!abortControllerRef.current) {
        updateSession(sessionId, { status: 'completed', progress: 100 });
        addLog(sessionId, "Task completed successfully.");
      } else {
        updateSession(sessionId, { status: 'stopped' });
      }

    } catch (error: any) {
      updateSession(sessionId, { status: 'failed' });
      addLog(sessionId, `Critical Error: ${error.message}`);
    }
  };

  const handleFileSelection = (files: FileList | File[]) => {
    const fileArray = Array.from(files);
    if (refImages.length + fileArray.length > 4) {
      alert("Maximum 4 reference images allowed.");
      return;
    }
    fileArray.forEach(file => {
      if (!file.type.startsWith('image/')) return;
      const reader = new FileReader();
      reader.onloadend = () => {
        setRefImages(prev => [...prev, reader.result as string]);
      };
      reader.readAsDataURL(file);
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      handleFileSelection(e.target.files);
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files) {
      handleFileSelection(e.dataTransfer.files);
    }
  };

  const handleImageSave = (id: string, newUrl: string, newTags: string[]) => {
    if (!activeSessionId) return;
    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        return {
          ...s,
          generatedImages: s.generatedImages.map(img => 
            img.id === id ? { ...img, url: newUrl, tags: newTags } : img
          )
        };
      }
      return s;
    }));
  };

  const filteredImages = activeSession 
    ? activeSession.generatedImages.filter(img => !activeFilterTag || img.tags.includes(activeFilterTag))
    : [];

  const uniqueTags = activeSession 
    ? Array.from(new Set(activeSession.generatedImages.flatMap(img => img.tags))) 
    : [];

  const downloadVisible = () => {
    if (!activeSession) return;
    filteredImages.forEach((img, idx) => {
      const link = document.createElement('a');
      link.href = img.url;
      link.download = `synth_${activeSession.id}_${idx}_${activeFilterTag || 'all'}.png`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    });
  };

  if (isCheckingKey) {
    return <div className="h-screen w-screen bg-black flex items-center justify-center text-slate-500">Initializing...</div>;
  }

  if (!hasApiKey) {
    return (
      <div className="flex h-screen w-screen bg-black items-center justify-center text-white relative overflow-hidden">
        <div className="z-10 text-center space-y-6 p-10 bg-slate-900/50 backdrop-blur-xl rounded-2xl border border-slate-700 max-w-lg shadow-2xl mx-4">
           <h1 className="text-3xl font-bold">Access Required</h1>
           <p className="text-slate-300">SynthVision uses Gemini 3 Pro. Please select a valid API Key.</p>
           <button onClick={handleSelectKey} className="bg-primary-600 text-white font-semibold py-3 px-6 rounded-lg">Connect API Key</button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-black text-slate-200 font-sans overflow-hidden">
      <Sidebar 
        sessions={sessions}
        activeSessionId={activeSessionId}
        onSelectSession={handleSelectSession}
        onNewSession={handleNewSession}
        onDeleteSession={(e, id) => {
          e.stopPropagation();
          setSessions(prev => prev.filter(s => s.id !== id));
          if (activeSessionId === id) setActiveSessionId(null);
        }}
      />

      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        <header className="h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur flex items-center justify-between px-6 z-10 shrink-0">
          <h2 className="text-lg font-semibold text-white">
            {activeSession ? activeSession.name : 'Data Forge Workbench'}
          </h2>
          <div className="flex items-center gap-3">
            <button 
               onClick={handleSelectKey}
               className="hidden md:flex text-xs text-slate-400 hover:text-white items-center gap-1 px-3 py-1.5 rounded border border-transparent hover:border-slate-700 transition-colors"
               title="Change API Key"
            >
               Key Active
            </button>
            <button 
              onClick={() => setIsSettingsOpen(true)}
              className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-800 border border-slate-700 hover:border-slate-500 text-xs text-slate-300 transition-colors"
            >
              <span className={`w-2 h-2 rounded-full ${activeModel.type === ModelType.GEMINI ? 'bg-green-500' : 'bg-blue-500'}`}></span>
              {activeModel.name}
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto scroll-smooth">
            <div className="p-6 border-b border-slate-800/50 bg-slate-900/20">
               <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6">
                  <div className="lg:col-span-4 space-y-3">
                    <div className="flex justify-between items-center">
                        <label className="text-sm font-medium text-slate-300">Reference Images (Max 4)</label>
                        <span className="text-xs text-slate-500">{refImages.length}/4</span>
                    </div>
                    <div 
                      onDragOver={handleDragOver}
                      onDragLeave={handleDragLeave}
                      onDrop={handleDrop}
                      className={`grid grid-cols-4 gap-2 p-1 rounded-xl transition-all duration-300 ${isDragging ? 'bg-primary-500/10 scale-[1.02] ring-2 ring-primary-500 ring-dashed' : ''}`}
                    >
                        {refImages.map((img, idx) => (
                        <div key={idx} className="aspect-square rounded-lg border border-slate-700 overflow-hidden relative group bg-slate-800 animate-in zoom-in-75 duration-200 shadow-lg">
                            <img src={img} alt="ref" className="w-full h-full object-contain" />
                            <div className="absolute top-1 left-1 bg-black/60 backdrop-blur-sm text-white text-[10px] px-1.5 py-0.5 rounded border border-white/20 font-mono shadow-sm">
                                REF {idx + 1}
                            </div>
                            <button 
                                onClick={() => setRefImages(prev => prev.filter((_, i) => i !== idx))}
                                className="absolute top-1 right-1 bg-black/60 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500/80"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
                            </button>
                        </div>
                        ))}
                        {refImages.length < 4 && (
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className={`aspect-square rounded-lg border-2 border-dashed transition-all flex flex-col items-center justify-center cursor-pointer ${isDragging ? 'border-primary-500 text-primary-500 bg-primary-500/5' : 'border-slate-700 text-slate-500 hover:border-primary-500 hover:text-primary-400 hover:bg-slate-800'}`}
                        >
                            <span className="text-xl font-bold">+</span>
                            <span className="text-[10px] mt-1 font-medium">Drop Here</span>
                        </button>
                        )}
                    </div>
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" multiple onChange={handleFileUpload} />
                  </div>

                  <div className="lg:col-span-6 space-y-3">
                    <label className="text-sm font-medium text-slate-300">Scenario Description</label>
                    <textarea 
                        value={promptInput}
                        onChange={(e) => setPromptInput(e.target.value)}
                        placeholder="Describe the desired output. To refer to specific images, use 'Ref 1', 'Ref 2', etc. Example: 'A robot (Ref 1) holding the skateboard (Ref 2) in a neon city...'"
                        className="w-full h-24 bg-slate-800 border border-slate-700 rounded-xl p-3 text-sm text-white placeholder-slate-500 focus:border-primary-500 outline-none resize-none transition-shadow focus:ring-1 focus:ring-primary-500/50 shadow-inner"
                    />
                  </div>

                  <div className="lg:col-span-2 space-y-3 flex flex-col">
                    <label className="text-sm font-medium text-slate-300">Count</label>
                    <select 
                        value={genCount}
                        onChange={(e) => setGenCount(Number(e.target.value))}
                        className="w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-sm text-white outline-none cursor-pointer hover:bg-slate-700 transition-colors"
                    >
                        {COUNT_OPTIONS.map(opt => <option key={opt} value={opt}>{opt} Images</option>)}
                    </select>
                    <button 
                        onClick={createSession}
                        disabled={!promptInput.trim()}
                        className="mt-auto w-full bg-primary-600 hover:bg-primary-500 disabled:opacity-50 disabled:cursor-not-allowed text-white text-sm font-semibold py-3 rounded-lg shadow-lg shadow-primary-900/40 transition-all active:scale-95"
                    >
                        Start Generation
                    </button>
                  </div>
               </div>
            </div>

            {activeSession && (
                <div className="p-6 pb-20 max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="h-px bg-slate-800 flex-1"></div>
                        <span className="text-slate-500 text-[10px] font-bold uppercase tracking-[0.2em]">Live Results</span>
                        <div className="h-px bg-slate-800 flex-1"></div>
                    </div>

                    <div className="bg-slate-900 border border-slate-800 rounded-xl p-6 mb-8 relative overflow-hidden shadow-2xl">
                        <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/5 rounded-full blur-3xl pointer-events-none -mr-16 -mt-16"></div>

                        <div className="flex justify-between items-end mb-4 relative z-10">
                            <div>
                                <div className="text-[10px] text-slate-400 uppercase tracking-widest font-bold mb-1">Active Pipeline</div>
                                <div className={`text-2xl font-bold flex items-center gap-3 ${
                                    activeSession.status === 'completed' ? 'text-green-400' : 
                                    activeSession.status === 'failed' ? 'text-red-400' : 
                                    'text-white'
                                }`}>
                                    {activeSession.status === 'generating' ? 'Synthesizing...' : activeSession.status.charAt(0).toUpperCase() + activeSession.status.slice(1)}

                                    {activeSession.status === 'generating' && (
                                    <button 
                                        onClick={() => stopGeneration(activeSession.id)}
                                        className="bg-red-500/20 hover:bg-red-500/30 text-red-500 text-[10px] font-bold px-3 py-1 rounded-full border border-red-500/50 transition-colors"
                                    >
                                        ABORT
                                    </button>
                                    )}
                                </div>
                            </div>
                            <div className="text-right">
                                <div className="text-3xl font-mono text-white">
                                {activeSession.generatedImages.length}<span className="text-slate-500 text-lg">/{activeSession.totalTarget}</span>
                                </div>
                            </div>
                        </div>

                        <div className="h-2 bg-slate-800 rounded-full overflow-hidden mb-6 relative z-10 shadow-inner">
                            <div 
                                className={`h-full transition-all duration-700 ease-out ${activeSession.status === 'stopped' ? 'bg-yellow-600' : 'bg-gradient-to-r from-primary-600 to-indigo-500'}`}
                                style={{ width: `${activeSession.progress}%` }}
                            ></div>
                        </div>

                         <div className="bg-black/40 rounded-lg p-3 font-mono text-[11px] text-slate-400 h-28 overflow-y-auto border border-slate-800/50 shadow-inner">
                            {activeSession.logs.map((log, i) => (
                                <div key={i} className="mb-1 leading-relaxed opacity-80 hover:opacity-100 transition-opacity">
                                  <span className="text-slate-600 mr-2">{log.split(']')[0]}]</span>
                                  <span>{log.split(']')[1]}</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="flex items-center justify-between mb-4">
                        <div className="flex gap-2">
                            {uniqueTags.length > 0 && (
                            <select 
                                value={activeFilterTag || ''} 
                                onChange={(e) => setActiveFilterTag(e.target.value || null)}
                                className="bg-slate-800 text-white text-[10px] font-bold border border-slate-700 rounded-lg px-3 py-1.5 outline-none hover:bg-slate-700 transition-colors"
                            >
                                <option value="">ALL SAMPLES</option>
                                {uniqueTags.map(tag => (
                                <option key={tag} value={tag}>{tag.toUpperCase()}</option>
                                ))}
                            </select>
                            )}
                        </div>
                        {filteredImages.length > 0 && (
                            <button 
                                onClick={downloadVisible}
                                className="text-[10px] font-bold text-slate-400 hover:text-white flex items-center gap-2 px-3 py-1.5 rounded-lg hover:bg-slate-800 transition-colors border border-transparent hover:border-slate-700"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path><polyline points="7 10 12 15 17 10"></polyline><line x1="12" y1="15" x2="12" y2="3"></line></svg>
                                EXPORT DATA
                            </button>
                        )}
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredImages.map((img) => (
                            <div 
                                key={img.id} 
                                onClick={() => setEditingImage(img)}
                                className="group relative aspect-square bg-slate-900 rounded-xl border border-slate-800 overflow-hidden hover:border-primary-500/50 transition-all duration-300 cursor-pointer flex items-center justify-center hover:shadow-2xl hover:shadow-primary-500/10 active:scale-95 shadow-lg"
                            >
                                <img src={img.url} alt="gen" className="w-full h-full object-contain p-2 transition-transform duration-500 group-hover:scale-105" />
                                {img.tags.length > 0 && (
