                           <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em]">Synthesized Prompt Variations</h4>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                             {activeSession.generatedPrompts.map((p, i) => (
