            )}

            {!activeSession && (
                <div className="h-64 flex flex-col items-center justify-center text-slate-600 space-y-4 animate-in fade-in duration-1000">
                    <div className="w-12 h-12 border border-slate-800 rounded-full flex items-center justify-center text-slate-700">
                        <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line></svg>
                    </div>
                    <p className="text-sm font-medium tracking-wide">Enter task details and start synthesis pipeline.</p>
                </div>
            )}
        </div>
      </main>

      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        configs={modelConfigs}
        activeConfigId={activeModelId}
        onSaveConfig={(config) => setModelConfigs(prev => [...prev, config])}
        onSelectActive={(id) => setActiveModelId(id)}
      />

      <ImageEditorModal 
        image={editingImage} 
        onClose={() => setEditingImage(null)}
        onSave={handleImageSave}
      />
    </div>
  );
};

